INSERT INTO curriculum_spine_elos (id, strand_id, elo_text, elo_order, created_at) VALUES
  ('MATH-G1-NS-ELO1', 'MATH-G1-NS', 'Using whole numbers - learners will meaningfully sequence and use a range of counting and grouping strategies.', 1, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-NS-ELO2', 'MATH-G1-NS', 'Learners will recognise, represent and partition whole numbers up to 20', 2, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-NS-ELO3', 'MATH-G1-NS', 'Students will be able to demonstrate their understanding of numbers and their values by comparing and ordering quantities up to 20 ', 3, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-NS-ELO4', 'MATH-G1-NS', 'Learner’s will comprehend the importance of the number ten and its role when counting from eleven to nineteen, as well as creating and solving simple problems involving place value', 4, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-ON-ELO1', 'MATH-G1-ON', 'Additive Thinking- Learners will understand the meaning of addition and subtraction and how they relate.', 5, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-ON-ELO2', 'MATH-G1-ON', 'Additive Thinking - Compute Fluently', 6, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-ON-ELO3', 'MATH-G1-ON', 'Multiplicative thinking - Learners will understand the meaning of multiplication and division and how they relate.', 7, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-PR-ELO1', 'MATH-G1-PR', 'Recognizing, Describing and Extending Patterns - Describe, create, extend and generalise patterns', 8, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-PR-ELO2', 'MATH-G1-PR', 'Learners will recognize, describe and extend for increasing and decreasing patterns', 9, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-PR-ELO3', 'MATH-G1-PR', 'Variables and Relationships - Representing Unknowns', 10, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-PR-ELO4', 'MATH-G1-PR', 'Variables and Relationships - Understanding and representing equivalence', 11, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-PR-ELO5', 'MATH-G1-PR', 'Variables and Relationships - Writing Expressions and Equations', 12, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO1', 'MATH-G1-GT', 'Explore and Analyze Geometric Shapes and Relationships   - Developing spatial sense', 13, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO2', 'MATH-G1-GT', 'Explore and Analyze Geometric Shapes and Relationships - Explore and Analyze Geometric Shapes and Relationships   - Sorting, patterning, and building with 2D & 3D Shapes  ', 14, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO3', 'MATH-G1-GT', 'Recognizing, Naming and Describing Shapes   - Analysing and describing shapes', 15, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO4', 'MATH-G1-GT', 'Recognizing, Naming and Describing Shapes   - Naming 2D & 3D shapes  ', 16, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO5', 'MATH-G1-GT', 'Recognizing, Naming and Describing Shapes   – Describing relationships between and among shapes', 17, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO6', 'MATH-G1-GT', 'Developing spatial sense   - Composing, Decomposing and Transforming Shapes - Combining Shapes', 18, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO7', 'MATH-G1-GT', 'Composing,   Decomposing and Transforming Shapes – Deconstructing Shapes', 19, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-GT-ELO8', 'MATH-G1-GT', 'Composing, Decomposing and Transforming Shapes   – Transforming Shapes', 20, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-M-ELO1', 'MATH-G1-M', 'Understanding What and How We Measure   - Developing an understanding of measurable attributes.', 21, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-M-ELO2', 'MATH-G1-M', 'Understanding What and How We Measure - Comparing and ordering based on measurable attributes', 22, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-M-ELO3', 'MATH-G1-M', 'Understanding What and How We Measure - Developing and applying non-standard units of measure.', 23, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-M-ELO4', 'MATH-G1-M', 'Understanding What and How We Measure - Developing and applying standard units of measure.', 24, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-DH-ELO1', 'MATH-G1-DH', 'Collecting, Organising and Displaying Data - Formulating questions that can be answered with data', 25, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-DH-ELO2', 'MATH-G1-DH', 'Collecting, Organising and Displaying Data - Collecting, organising, displaying and communicating data', 26, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-DH-ELO3', 'MATH-G1-DH', 'Using Statistical Methods to Analyze Data - Describing data sets', 27, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-DH-ELO4', 'MATH-G1-DH', 'Using Statistical Methods to Analyze Data - Developing and applying methods to analyse data sets', 28, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G1-DH-ELO5', 'MATH-G1-DH', 'Understanding and Applying Concepts of Probability - Predicting and describing the likelihood of an events.', 29, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G1-LS-ELO1', 'LANG-G1-LS', 'The learner will explore, use, and critically apply oral language for pleasure, personal growth, to form and foster relationships and, to develop an appreciation of and celebration of culture and of oral languages.', 30, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G1-RV-ELO1', 'LANG-G1-RV', 'The learner will demonstrate a variety of ways to use background knowledge and interests to select and engage critically with a range of culturally diverse paper-based, visual, and digital texts for pleasure and personal growth.', 31, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G1-RV-ELO2', 'LANG-G1-RV', 'The learner will interact with understanding and critical thought to a variety of genres and text forms using comprehension strategies, vocabulary, language structures, and graphophonic cues.', 32, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G1-RV-ELO3', 'LANG-G1-RV', 'Students will develop their understanding of how an author’s purpose and style, genre, text form, text features and choice of vocabulary, language, influence the meaning of text and define the author’s craft.', 33, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G1-WR-ELO1', 'LANG-G1-WR', 'Learners will generate, gather and organize thoughts to explore, clarify and reflect on ideas, feelings and experiences as they create a written or representative draft, independently and collaboratively, for a range of audiences and purposes.', 34, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G1-WR-ELO2', 'LANG-G1-WR', 'learners will revise the organization, and language use (vocabulary and grammar) of drafted writing or representation, collaboratively and independently, for a variety of purposes and audiences.', 35, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G1-WR-ELO3', 'LANG-G1-WR', 'learners will use their knowledge of spoken language, written language and writing conventions to refine the precision and enhance the meaning and clarity of their written work.', 36, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-WLS-ELO1', 'SCIENCE-G1-WLS', 'Learners will be able to plan and conduct investigations to provide evidence that vibrating materials can make sound and that sound can make materials vibrate.', 37, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-WLS-ELO2', 'SCIENCE-G1-WLS', 'Make observations to construct an evidence-based account, that objects can be seen only when illuminated.', 38, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-WLS-ELO3', 'SCIENCE-G1-WLS', 'Plan and conduct an investigation to determine the effect of placing objects made with different materials in the path of a beam of light.', 39, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-WLS-ELO4', 'SCIENCE-G1-WLS', 'Use tools and materials to design and build a device that uses light or sound to solve the problem of communicating over a distance.', 40, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-SFI-ELO1', 'SCIENCE-G1-SFI', 'Use materials to design a solution to a human problem by mimicking how plants and/or animals use their external parts to help them survive, grow and meet their needs.', 41, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-SFI-ELO2', 'SCIENCE-G1-SFI', 'Read texts and use media to determine patterns in behaviour of parent and offspring that help offspring survive.', 42, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-SFI-ELO3', 'SCIENCE-G1-SFI', 'Make observations to construct an evidence-based account that young plants and animals are like, but not exactly like their parents. ', 43, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-SS-ELO1', 'SCIENCE-G1-SS', 'Use observations of the sun, moon, and stars to describe patterns that can be predicted.', 44, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G1-SS-ELO2', 'SCIENCE-G1-SS', 'Make observations at different times of the year to relate the amount of daylight to the time of year.', 45, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-HCT-ELO1', 'SS-G1-HCT', 'To understand that our celebrations help us build pride in our identity.', 46, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-CP-ELO1', 'SS-G1-CP', 'To understand that we have roles and responsibilities in our families, school, and community - Section 1: What are our roles and responsibilities in our Family?', 47, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-CP-ELO2', 'SS-G1-CP', 'To understand that we have roles and responsibilities in our families, school, and community - Section 2: What are our roles and responsibilities in our extended Family?', 48, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-CP-ELO3', 'SS-G1-CP', 'To understand that we have roles and responsibilities in our families, school, and community - Section 3: What are our roles and responsibilities in our Family and School?', 49, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-CP-ELO4', 'SS-G1-CP', 'To understand that we have roles and responsibilities in our families, school, and community - Section 4: Who are leaders and what is their role?', 50, '2026-02-21T17:24:20.767466+00:00');
INSERT INTO curriculum_spine_elos (id, strand_id, elo_text, elo_order, created_at) VALUES
  ('SS-G1-CP-ELO5', 'SS-G1-CP', 'To understand that we have roles and responsibilities in our families, school, and community - Section 5: What are our roles and responsibilities in of adults?', 51, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-ST-ELO1', 'SS-G1-ST', 'To understand how we shape the local environment and the local environment shapes who we are and how we live. - Section 1: What is a Neighbourhood?', 52, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-ST-ELO2', 'SS-G1-ST', 'To understand how we shape the local environment and the local environment shapes who we are and how we live. - Section 2: How does where we live impact us?', 53, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-ST-ELO3', 'SS-G1-ST', 'To understand how we shape the local environment and the local environment shapes who we are and how we live. - Section 3: What is cardinal direction and how is it useful to me?', 54, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-ST-ELO4', 'SS-G1-ST', 'To understand how we shape the local environment and the local environment shapes who we are and how we live. - Section 4: How do we interact with our local environment?', 55, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-ST-ELO5', 'SS-G1-ST', 'To understand how we shape the local environment and the local environment shapes who we are and how we live. - Section 5: How do we stay safe where we live?', 56, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-EDM-ELO1', 'SS-G1-EDM', 'To be aware that we all have things we need and things we want - Section 1: What are needs, wants, goods and services?', 57, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-EDM-ELO2', 'SS-G1-EDM', 'To be aware that we all have things we need and things we want - Section 2: What are examples of goods and services and how do we obtain them?', 58, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-EDM-ELO3', 'SS-G1-EDM', 'To be aware that we all have things we need and things we want - Section 3: What are resources and how do we obtain and manage them?', 59, '2026-02-21T17:24:20.767466+00:00'),
  ('SS-G1-EDM-ELO4', 'SS-G1-EDM', 'To be aware that we all have things we need and things we want - Section 4: How do we travel safely?', 60, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-NS-ELO1', 'MATH-G2-NS', 'Whole Number - Saying Number Sequence, Meaningful Counting and Skip Counting', 61, '2026-02-21T17:24:20.767466+00:00'),
