  ('MATH-G2-ON-ELO1', 'MATH-G2-ON', 'Additive Thinking - Understanding the meaning of addition and subtraction and how they relate.', 67, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-ON-ELO2', 'MATH-G2-ON', 'Additive Thinking - Compute Fluently', 68, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-ON-ELO3', 'MATH-G2-ON', 'Multiplicative Thinking - Understanding the meaning of multiplication and division and how they relate', 69, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-PR-ELO1', 'MATH-G2-PR', 'Learners will create and extend simple patterns, repeating and growing patterns.', 70, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-PR-ELO2', 'MATH-G2-PR', 'Recognizing, Describing and Extending Patterns - Increasing and Decreasing Patterns', 71, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-PR-ELO3', 'MATH-G2-PR', 'Identify when symbols are being used as variables, and describe how they are being used.', 72, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-PR-ELO4', 'MATH-G2-PR', 'Variables and Relationships - Understanding and representing equivalence.', 73, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-PR-ELO5', 'MATH-G2-PR', 'Variables and Relationships - Writing Expressions and Equations', 74, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-GT-ELO1', 'MATH-G2-GT', 'Exploring and Analyzing Geometric Shapes and Relationships- Developing Spatial Sense', 75, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-GT-ELO2', 'MATH-G2-GT', 'Exploring and Analyzing Geometric Shapes and Relationships - Sorting, patterning, and building with 2D and 3D Shapes.', 76, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-GT-ELO3', 'MATH-G2-GT', 'Recognizing, Naming and Describing Shapes - Analyzing and describing shapes', 77, '2026-02-21T17:24:20.767466+00:00'),
