  ('MATH-G2-DH-ELO1', 'MATH-G2-DH', 'Learners will develop statistical literacy by recognizing topics for investigation and formulating simple questions that can be answered with data.', 90, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-DH-ELO2', 'MATH-G2-DH', 'Collecting, Organising and Displaying Data - Collecting, organising, displaying and communicating data.', 91, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-DH-ELO3', 'MATH-G2-DH', 'Using Statistical Methods to Analyze Data - Describing data sets', 92, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-DH-ELO4', 'MATH-G2-DH', 'Using Statistical Methods to Analyse Data - Developing and applying methods to analyse data sets.', 93, '2026-02-21T17:24:20.767466+00:00'),
  ('MATH-G2-DH-ELO5', 'MATH-G2-DH', 'Using Statistical Methods to Analyse Data - Predicting and describing the likelihood of events.', 94, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G2-LS-ELO1', 'LANG-G2-LS', 'The learner will explore, use, and critically apply oral language for pleasure, personal growth, to form and foster relationships and to develop an appreciation and celebration of culture and of oral languages.', 95, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G2-RV-ELO1', 'LANG-G2-RV', 'The learner will demonstrate a variety of ways to select and engage critically with a range of culturally diverse paper based, visual and digital texts for a variety of purposes, including pleasure, and personal growth.', 96, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G2-RV-ELO2', 'LANG-G2-RV', 'The learner will demonstrate a variety of ways to use background knowledge and interests to select and engage critically with a range of culturally diverse paper based, visual, and digital texts for pleasure and personal growth.', 97, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G2-RV-ELO3', 'LANG-G2-RV', 'Students will develop their understanding of how an author’s purpose and style, genre, text form, text features and choice of vocabulary, and language influence the meaning of text and define the author’s craft.', 98, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G2-WR-ELO1', 'LANG-G2-WR', 'The learner will generate, gather, and organize thoughts to explore, clarify and reflect on ideas, feelings, and experiences as they create a written or representative draft, independently and collaboratively, for a range of audiences and purposes.', 99, '2026-02-21T17:24:20.767466+00:00'),
  ('LANG-G2-WR-ELO2', 'LANG-G2-WR', 'The learner will revise the organization, and language use (vocabulary and grammar) drafted writing or representation, collaboratively and independently, for a variety of purposes and audiences.', 100, '2026-02-21T17:24:20.767466+00:00');
INSERT INTO curriculum_spine_elos (id, strand_id, elo_text, elo_order, created_at) VALUES
  ('LANG-G2-WR-ELO3', 'LANG-G2-WR', 'The learner will use their knowledge of spoken language, written language and writing conventions to refine the precision and enhance the meaning and clarity of their written work.', 101, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-SPM-ELO1', 'SCIENCE-G2-SPM', 'Plan and conduct an investigation to describe and classify different kinds of materials by their observable properties.', 102, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-SPM-ELO2', 'SCIENCE-G2-SPM', 'Analyze data obtained from testing different materials to determine which materials have the properties that are best suited for an intended purpose.', 103, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-SPM-ELO3', 'SCIENCE-G2-SPM', 'Make observations to construct an evidence-based account of how an object made of a small set of pieces can be disassembled and made into a new object.', 104, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-SPM-ELO4', 'SCIENCE-G2-SPM', 'Construct an argument with evidence that some changes caused by heating or cooling can be reversed and some cannot.', 105, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-IRE-ELO1', 'SCIENCE-G2-IRE', 'Plan and conduct an investigation to determine if plants need sunlight and water to grow.', 106, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-IRE-ELO2', 'SCIENCE-G2-IRE', 'Develop a simple model that mimics the function of an animal in dispersing seeds or pollinating plants. Make observations of plants and animals to compare the diversity of life in different habitats', 107, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-ES-ELO1', 'SCIENCE-G2-ES', 'Use information from several sources to provide evidence that Earth events can occur quickly or slowly.', 108, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-ES-ELO2', 'SCIENCE-G2-ES', 'Compare multiple solutions designed to slow or prevent wind or water from changing the shape of the land.', 109, '2026-02-21T17:24:20.767466+00:00'),
  ('SCIENCE-G2-ES-ELO3', 'SCIENCE-G2-ES', 'Develop a model to represent the shapes and kinds of land and bodies of water in an area.', 110, '2026-02-21T17:24:20.767466+00:00'),
